-- This program takes two input integers n and k, and calculates the binomial coefficient C(n,k).
-- The result will be output as a single integer value.

-- First, we will define the factorial function.

function factorial(n: integer) return integer is
    variable result: integer := 1;
begin
    for I in 1 to n loop
        result := result * i;
    end loop;
    return result;
end factorial;

-- Next, we will define the main program.

entity binomial_coeff is
    port (n, k: in integer;
          coefficient: out integer);
end binomial_coeff;

architecture Behavioral of binomial_coeff is
begin
    process (n, k)
    begin
        if n >= k and k >= 0 then
            coefficient <= (factorial(n) / (factorial(k) * factorial(n-k)));
        else
            coefficient <= 0;
        end if;
    end process;
end Behavioral;

-- The main process includes a conditional statement to check if n is greater than or equal to k, and if k is greater than or equal to 0.
-- If the condition is true, the binomial coefficient is calculated using the formula C(n,k) = n! / (k! * (n-k)!) and stored in the output variable "coefficient".
-- If the condition is false, the output variable "coefficient" is set to 0.
-- This program can also be compiled and tested with a testbench.

